import { SchemaDef, CanonicalSchemaDef } from "./schema/types.js";
import { normalizeSchema } from "./schema/normalize.js";
import { validateSchemaDef, validateQueryInput } from "./schema/validation.js";
import { introspect } from "./schema/introspect.js";
import { diffSchemas } from "./schema/diff.js";
import { generateSQL } from "./schema/sql.js";
import { QueryBuilder } from "./query/builder.js";
import { Planner } from "./query/planner.js";
import { Compiler, Compiled } from "./query/compiler.js";
import { KadakClient } from "./exec/client.js";
import { transaction } from "./exec/tx.js";
import { analyzePlan } from "./analyzer/rules.js";
import { normalizeRows } from "./exec/normalize.js";

export interface KadakDataPromise<T> extends Promise<T> {
  toSQL: () => Compiled;
  explain: () => Promise<Record<string, unknown>[]>;
}

export function kadak(config: { url: string }) {
  const client = new KadakClient(config.url);
  let normalizedSchema: CanonicalSchemaDef = {};

  return {
    schema(userSchema: SchemaDef) {
      const validated = validateSchemaDef(userSchema);
      normalizedSchema = normalizeSchema(validated as SchemaDef);
      return {
        async push() {
          await transaction(client, async (tx) => {
            const currentDbSchema = await introspect(tx);
            const ops = diffSchemas(normalizedSchema, currentDbSchema);
            const statements = generateSQL(ops);
            for (const sql of statements) {
              await tx.query(sql);
            }
          });
        }
      };
    },

    data<T = unknown>(queryInput: Record<string, unknown>): KadakDataPromise<T[]> {
      const validatedQuery = validateQueryInput(queryInput);
      const rootTable = Object.keys(validatedQuery)[0];
      const qBuilder = new QueryBuilder(normalizedSchema);
      const ast = qBuilder.buildAST(rootTable, validatedQuery);
      const planner = new Planner(normalizedSchema);
      const plan = planner.plan(ast.root);
      const compiler = new Compiler(normalizedSchema);
      const compiled = compiler.compile(plan);
      
      const warnings = analyzePlan(plan);
      if (warnings.length > 0) {
        console.warn("Kadak Analyzer Warnings:");
        warnings.forEach(w => console.warn(`⚠️  ${w.message}\n   Suggestion: ${w.suggestion}`));
      }

      const executor = {
        async execute(): Promise<T[]> {
          const rows = await client.execute(compiled);
          return normalizeRows(rows, ast) as unknown as T[];
        },
        toSQL() {
          return compiled;
        },
        async explain() {
          return await client.explain(compiled);
        }
      };

      const promise = executor.execute() as KadakDataPromise<T[]>;
      promise.toSQL = () => executor.toSQL();
      promise.explain = () => executor.explain();

      return promise;
    },

    async tx<T>(callback: (txClient: import("pg").PoolClient) => Promise<T>) {
      return transaction(client, async (txClient) => {
         return callback(txClient);
      });
    },

    async close() {
      await client.close();
    }
  };
}

export * from "./schema/index.js";
export * from "./query/index.js";
export * from "./exec/index.js";
export * from "./analyzer/index.js";
