import { Plan } from "./planner.js";
import { CanonicalSchemaDef } from "../schema/types.js";
import { PredicateValue } from "./ast.js";

export type Compiled = {
  text: string;
  values: PredicateValue[];
};

export class Compiler {
  constructor(private schema: CanonicalSchemaDef = {}) {}

  public compile(plan: Plan): Compiled {
    const values: PredicateValue[] = [];
    let sql = "SELECT ";

    // SELECT with aliased columns: alias__column
    const selectFields: string[] = [];
    for (const s of plan.select) {
      const tableDef = this.schema[s.table];
      if (tableDef) {
        // Add ID column if it exists or is expected
        selectFields.push(`${s.tableAlias}.id AS ${s.tableAlias}__id`);
        for (const colName of Object.keys(tableDef)) {
          if (colName === 'id') continue;
          selectFields.push(`${s.tableAlias}.${colName} AS ${s.tableAlias}__${colName}`);
        }
      } else {
        // Fallback for unknown tables
        selectFields.push(`${s.tableAlias}.*`);
      }
    }
    sql += selectFields.join(", ") + "\n";

    // FROM
    sql += `FROM ${plan.from.table} ${plan.from.alias}\n`;

    // JOINS
    for (const join of plan.joins) {
      const onClauses = join.on.map(c => `${c.left} = ${c.right}`).join(" AND ");
      sql += `LEFT JOIN ${join.table} ${join.alias} ON ${onClauses}\n`;
    }

    // WHERE
    if (plan.where.length > 0) {
      const whereClauses = plan.where.map(p => {
        if (p.op === "eq") {
           values.push(p.value);
           return `${p.column} = $${values.length}`;
        }
        return "";
      }).filter(Boolean).join(" AND ");
      if (whereClauses) {
        sql += `WHERE ${whereClauses}\n`;
      }
    }

    // ORDER BY
    if (plan.orderBy && plan.orderBy.length > 0) {
      const orders = plan.orderBy.map(o => `${plan.from.alias}.${o.column} ${o.dir.toUpperCase()}`).join(", ");
      sql += `ORDER BY ${orders}\n`;
    }

    // LIMIT
    if (plan.limit) {
      sql += `LIMIT ${plan.limit}\n`;
    }

    return { text: sql.trim(), values };
  }
}
