import { QueryAST, ASTNode } from "../query/ast.js";

interface NormalizedObject {
  id: unknown;
  [key: string]: unknown;
}

export function normalizeRows(rows: Record<string, unknown>[], ast: QueryAST): NormalizedObject[] {
  const root = ast.root;
  const store: Record<string, Map<unknown, NormalizedObject>> = {};

  // Initialize maps for each node in AST
  const initializeMaps = (node: ASTNode) => {
    store[node.alias] = new Map<unknown, NormalizedObject>();
    for (const rel of node.relations) {
      initializeMaps(rel);
    }
  };
  initializeMaps(root);

  for (const row of rows) {
    processNode(root, row, store);
  }

  // Return only root-level unique items
  return Array.from(store[root.alias].values());
}

function processNode(
  node: ASTNode,
  row: Record<string, unknown>,
  store: Record<string, Map<unknown, NormalizedObject>>
): NormalizedObject | undefined {
  const prefix = `${node.alias}__`;
  const id = row[`${prefix}id`];
  
  if (id === null || id === undefined) return undefined;

  let obj = store[node.alias].get(id);
  if (!obj) {
    obj = { id };
    for (const [key, val] of Object.entries(row)) {
      if (key.startsWith(prefix)) {
        obj[key.replace(prefix, "")] = val;
      }
    }
    store[node.alias].set(id, obj);
  }

  for (const rel of node.relations) {
    const relObj = processNode(rel, row, store);
    if (relObj) {
      const relName = rel.table;
      if (!obj[relName]) obj[relName] = [] as NormalizedObject[];
      const children = obj[relName] as NormalizedObject[];
      if (!children.some((item) => item.id === relObj.id)) {
        children.push(relObj);
      }
    }
  }

  return obj;
}
