import { ASTNode, Predicate } from "./ast.js";
import { CanonicalSchemaDef } from "../schema/types.js";

export type Plan = {
  from: { table: string; alias: string };
  joins: Array<{
    type: "left";
    table: string;
    alias: string;
    on: { left: string; right: string }[];
  }>;
  where: Predicate[];
  orderBy?: { column: string; dir: "asc" | "desc" }[];
  limit?: number;
  select: Array<{ table: string; tableAlias: string; selectAll: boolean }>;
};

export class Planner {
  constructor(private schema: CanonicalSchemaDef = {}) {}

  public plan(astRoot: ASTNode): Plan {
    const plan: Plan = {
      from: { table: astRoot.table, alias: astRoot.alias },
      joins: [],
      where: [],
      select: [],
      limit: astRoot.limit,
      orderBy: astRoot.orderBy
    };

    this.traverse(astRoot, plan);
    return plan;
  }

  private traverse(node: ASTNode, plan: Plan, parentAlias?: string, parentTable?: string) {
    plan.select.push({ table: node.table, tableAlias: node.alias, selectAll: node.selectAll });

    if (node.where) {
      for (const p of node.where) {
         if (p.op === "eq") {
           plan.where.push({ ...p, column: `${node.alias}.${p.column}` });
         } else {
           plan.where.push(p);
         }
      }
    }

    if (parentAlias && parentTable) {
      const onCondition = { 
        left: `${parentAlias}.id`, 
        right: `${node.alias}.${parentTable.slice(0, -1)}_id`
      };
      plan.joins.push({
        type: "left",
        table: node.table,
        alias: node.alias,
        on: [onCondition]
      });
    }

    for (const relation of node.relations) {
      this.traverse(relation, plan, node.alias, node.table);
    }
  }
}
