import { QueryAST, ASTNode, Predicate, PredicateValue } from "./ast.js";
import { CanonicalSchemaDef } from "../schema/types.js";

export class QueryBuilder {
  private aliasCounter = 0;

  constructor(private schema: CanonicalSchemaDef = {}) {}

  private getAlias(): string {
    return `t${this.aliasCounter++}`;
  }

  private buildWhere(whereObj: Record<string, PredicateValue>): Predicate[] {
    const predicates: Predicate[] = [];
    for (const [key, value] of Object.entries(whereObj)) {
      predicates.push({ op: "eq", column: key, value });
    }
    return predicates;
  }

  public buildAST(rootTable: string, queryInput: Record<string, unknown>): QueryAST {
    const rootNode = this.parseNode(rootTable, queryInput[rootTable] as Record<string, unknown>);
    return { root: rootNode };
  }

  private parseNode(tableName: string, input: Record<string, unknown>): ASTNode {
    const alias = this.getAlias();
    const relations: ASTNode[] = [];
    let where: Predicate[] | undefined;
    let limit: number | undefined;
    let orderBy: { column: string; dir: "asc" | "desc" }[] | undefined;

    for (const [key, value] of Object.entries(input)) {
      if (key === "where") {
        where = this.buildWhere(value as Record<string, PredicateValue>);
      } else if (key === "limit") {
        limit = value as number;
      } else if (key === "orderBy") {
        orderBy = Object.entries(value as Record<string, string>).map(([col, dir]) => ({
          column: col,
          dir: dir as "asc" | "desc",
        }));
      } else {
        // Key represents a relation if it's an object. For boolean `true`, it means fetch relation with no filters.
        const relationInput = value === true ? {} : (value as Record<string, unknown>);
        relations.push(this.parseNode(key, relationInput));
      }
    }

    return {
      table: tableName,
      alias,
      where,
      limit,
      orderBy,
      relations,
      selectAll: true,
    };
  }
}
