import pg from "pg";
import { Compiled } from "../query/compiler.js";

export class KadakClient {
  private pool: pg.Pool;

  constructor(connectionString: string) {
    this.pool = new pg.Pool({ connectionString });
  }

  public async execute(compiled: Compiled): Promise<Record<string, unknown>[]> {
    const res = await this.pool.query(compiled.text, compiled.values);
    return res.rows as Record<string, unknown>[];
  }

  public async explain(compiled: Compiled): Promise<Record<string, unknown>[]> {
    const explainSql = `EXPLAIN ANALYZE ${compiled.text}`;
    const res = await this.pool.query(explainSql, compiled.values);
    return res.rows as Record<string, unknown>[];
  }

  public async getClient(): Promise<pg.PoolClient> {
    return await this.pool.connect();
  }

  public async close() {
    await this.pool.end();
  }
}
